import React from 'react';
import { Link } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

export default function NotFound() {
  return (
    <main className="section container text-center" style={{ padding: '5rem 1rem' }}>
      <Helmet>
        <title>Page not found | Nova Shop</title>
      </Helmet>
      <h1 style={{ fontSize: '5rem', marginBottom: '0.5rem' }}>404</h1>
      <p style={{ marginBottom: '1.5rem', fontSize: '1.125rem' }}>This page does not exist.</p>
      <Link to="/" className="btn btn-primary">
        Back to home
      </Link>
    </main>
  );
}
